#include<bits/stdc++.h>
using namespace std;
long long g=0,cg=0,n,m,t=0;
vector<long long>a(100005);
int main() {
	cin>>n>>m;
	for(int i=0; i<n; i++) {
		cin>>a[i];
		t+=a[i];
	}
	for(int j=0; j<n; j++) {
		long long gg=m-a[j];
		cg+=gg;
		if(cg<0) {
			cg=0;
		}
		g=max(g,cg);
	}
	cout<<t+g;
	return 0;
}
